def maxSumOfKSubarrays(nums, k, m):
    n = len(nums)
    prefix_sum = [0] * (n + 1)

    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    max_sum = [[float('-inf')] * (k + 1) for _ in range(n + 1)]
    max_sum[0][0] = 0

    for j in range(1, k + 1):
        for i in range(j * m, n + 1):
            for length in range(m, i - (j - 1) * m + 1):
                current_sum = prefix_sum[i] - prefix_sum[i - length]
                max_sum[i][j] = max(max_sum[i][j], max_sum[i - length][j - 1] + current_sum)

    return max(max_sum[i][k] for i in range(n + 1))

