def maxSumOfKSubarrays(nums, k, m):
    n = len(nums)
    if k * m > n:
        return 0

    # Calculate prefix sums
    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    # Calculate max sum for each subarray of length at least m
    max_sum = [0] * (n + 1)
    for i in range(m, n + 1):
        max_sum[i] = max(max_sum[i - 1], prefix_sum[i] - prefix_sum[i - m])

    # Dynamic programming to find the maximum sum of k non-overlapping subarrays
    dp = [[0] * (k + 1) for _ in range(n + 1)]
    for j in range(1, k + 1):
        for i in range(m, n + 1):
            dp[i][j] = max(dp[i - 1][j], dp[i - m][j - 1] + max_sum[i])

    return dp[n][k]

def maxSumOfKSubarrays(nums, k, m):
    n = len(nums)
    prefix_sum = [0] * (n + 1)

    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    def get_sum(l, r):
        return prefix_sum[r + 1] - prefix_sum[l]

    dp = [[0] * (k + 1) for _ in range(n + 1)]

    for j in range(1, k + 1):
        for i in range(m * j, n + 1):
            for p in range(m - 1, i - m + 1):
                dp[i][j] = max(dp[i][j], dp[p][j - 1] + get_sum(p, i - 1))

    return max(dp[i][k] for i in range(n + 1))

