    if n < k * m:
        return 0

    # Precompute the prefix sums
    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + nums[i]

    # Function to get the sum of a subarray from l to r (inclusive)
    def get_sum(l, r):
        return prefix_sum[r + 1] - prefix_sum[l]

    # dp[i][j] will store the maximum sum we can get with j subarrays using the first i elements
    dp = [[0] * (k + 1) for _ in range(n + 1)]

    for j in range(1, k + 1):
        for i in range(j * m, n + 1):
            for length in range(m, i - (j - 1) * m + 1):
                dp[i][j] = max(dp[i][j], dp[i - length][j - 1] + get_sum(i - length, i - 1))

    return dp[n][k]

